import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import {
  createContext,
  forwardRef,
  useContext,
  type ComponentProps,
  type ComponentRef,
} from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { Button } from '../button';
import { Input } from '../input';
import styles from './InputGroup.module.css';

type InputGroupSize = NonNullable<ComponentProps<typeof Input>['size']>;

const InputGroupSizeContext = createContext<InputGroupSize>('md');

const InputGroupRoot = forwardRef<
  HTMLDivElement,
  HTMLArkProps<'div'> & {
    size?: InputGroupSize;
  }
>(function InputGroupRoot({ children, className, size = 'md', ...props }, ref) {
  return (
    <InputGroupSizeContext.Provider value={size}>
      <ark.div
        ref={ref}
        data-scope="input-group"
        data-part="root"
        data-slot="input-group-root"
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      >
        {children}
      </ark.div>
    </InputGroupSizeContext.Provider>
  );
});

const InputGroupInput = forwardRef<ComponentRef<typeof Input>, ComponentProps<typeof Input>>(
  function InputGroupInput({ className, size, ...props }, ref) {
    const groupSize = useContext(InputGroupSizeContext);

    return (
      <Input
        ref={ref}
        data-slot="input-group-input"
        className={clsx(styles.input, normalizeClassName(className))}
        size={size ?? groupSize}
        {...props}
      />
    );
  },
);

const InputGroupAddon = forwardRef<HTMLSpanElement, HTMLArkProps<'span'>>(function InputGroupAddon(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="input-group"
      data-part="addon"
      data-slot="input-group-addon"
      className={clsx(styles.addon, normalizeClassName(className))}
      {...props}
    />
  );
});

const InputGroupText = forwardRef<HTMLSpanElement, HTMLArkProps<'span'>>(function InputGroupText(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      data-scope="input-group"
      data-part="text"
      data-slot="input-group-text"
      className={clsx(styles.text, normalizeClassName(className))}
      {...props}
    />
  );
});

const InputGroupButton = forwardRef<HTMLButtonElement, ComponentProps<typeof Button>>(
  function InputGroupButton(
    { className, variant = 'ghost', size, type = 'button', ...props },
    ref,
  ) {
    const groupSize = useContext(InputGroupSizeContext);

    return (
      <Button
        ref={ref}
        data-slot="input-group-button"
        className={clsx(styles.button, normalizeClassName(className))}
        variant={variant}
        size={size ?? groupSize}
        type={type}
        {...props}
      />
    );
  },
);

const InputGroup = Object.assign(InputGroupRoot, {
  Root: InputGroupRoot,
  Input: InputGroupInput,
  Addon: InputGroupAddon,
  Text: InputGroupText,
  Button: InputGroupButton,
});

export { InputGroup };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--input-group-width, 100%);
    max-width: var(--input-group-max-width, none);
    min-height: var(--input-group-height, var(--input-group-height-md, var(--size-md)));
    align-items: stretch;
    overflow: hidden;
    border: var(--input-group-border-width, var(--border-width-sm))
      var(--input-group-border-style, solid) var(--input-group-border-color, var(--color-border));
    border-radius: var(--input-group-radius, var(--radius-md));
    background-color: var(--input-group-bg, var(--color-background));
    color: var(--input-group-color, var(--color-foreground));
    outline: var(
        --input-group-focus-ring-width,
        var(--input-group-border-width, var(--border-width-sm))
      )
      solid transparent;
    outline-offset: var(--input-group-focus-ring-offset, -1px);
    transition:
      border-color var(--input-group-transition, var(--transition-default)),
      outline-color var(--input-group-transition, var(--transition-default)),
      opacity var(--input-group-transition, var(--transition-default));

    &:focus-within {
      outline-color: var(--input-group-focus-ring-color, var(--color-ring));
    }

    &:has(
      [data-slot='input-group-input'][data-invalid],
      [data-slot='input-group-input'][aria-invalid='true']
    ) {
      border-color: var(--input-group-border-color-invalid, var(--color-destructive));

      &:focus-within {
        outline-color: var(--input-group-border-color-invalid, var(--color-destructive));
      }
    }

    &:has(
      [data-slot='input-group-input'][data-disabled],
      [data-slot='input-group-input']:disabled
    ) {
      opacity: var(--input-group-disabled-opacity, var(--opacity-disabled));
    }

    &:has(
      [data-slot='input-group-input'][data-readonly],
      [data-slot='input-group-input']:read-only
    ) {
      border-color: var(
        --input-group-readonly-border-color,
        var(--input-group-border-color, var(--color-border))
      );
      background-color: var(
        --input-group-readonly-bg,
        var(--input-group-bg, var(--color-background))
      );
      color: var(--input-group-readonly-color, var(--input-group-color, var(--color-foreground)));
    }

    &[data-size='xs'] {
      --input-group-height: var(--input-group-height-xs, var(--size-sm));
      --input-group-addon-padding-x: var(--input-group-addon-padding-x-xs, 0.625rem);
      --input-group-font-size: var(--input-group-font-size-xs, var(--text-xs));
      --input-group-line-height: var(--input-group-line-height-xs, var(--line-height-text-xs));
      --input-group-input-padding-x: var(--input-group-input-padding-x-xs, 0.625rem);
      --input-group-input-padding-y: var(--input-group-input-padding-y-xs, 0.25rem);
    }

    &[data-size='sm'] {
      --input-group-height: var(--input-group-height-sm, var(--size-sm));
      --input-group-addon-padding-x: var(--input-group-addon-padding-x-sm, 0.75rem);
      --input-group-font-size: var(--input-group-font-size-sm, var(--text-sm));
      --input-group-line-height: var(--input-group-line-height-sm, var(--line-height-text-sm));
      --input-group-input-padding-x: var(--input-group-input-padding-x-sm, 0.75rem);
      --input-group-input-padding-y: var(--input-group-input-padding-y-sm, 0.3125rem);
    }

    &[data-size='md'] {
      --input-group-height: var(--input-group-height-md, var(--size-md));
      --input-group-addon-padding-x: var(--input-group-addon-padding-x-md, 0.875rem);
      --input-group-font-size: var(--input-group-font-size-md, var(--text-md));
      --input-group-line-height: var(--input-group-line-height-md, var(--line-height-text-md));
      --input-group-input-padding-x: var(--input-group-input-padding-x-md, 0.875rem);
      --input-group-input-padding-y: var(--input-group-input-padding-y-md, var(--spacing-1));
    }

    &[data-size='lg'] {
      --input-group-height: var(--input-group-height-lg, var(--size-xl));
      --input-group-addon-padding-x: var(--input-group-addon-padding-x-lg, 1rem);
      --input-group-font-size: var(--input-group-font-size-lg, var(--text-lg));
      --input-group-line-height: var(--input-group-line-height-lg, var(--line-height-text-lg));
      --input-group-input-padding-x: var(--input-group-input-padding-x-lg, 1rem);
      --input-group-input-padding-y: var(--input-group-input-padding-y-lg, 0.625rem);
    }

    &[data-size='xl'] {
      --input-group-height: var(--input-group-height-xl, 3rem);
      --input-group-addon-padding-x: var(--input-group-addon-padding-x-xl, 1.125rem);
      --input-group-font-size: var(--input-group-font-size-xl, var(--text-lg));
      --input-group-line-height: var(--input-group-line-height-xl, var(--line-height-text-lg));
      --input-group-input-padding-x: var(--input-group-input-padding-x-xl, 1.125rem);
      --input-group-input-padding-y: var(--input-group-input-padding-y-xl, 0.75rem);
    }
  }

  .input {
    min-width: 0;
    min-height: 0;
    flex: 1 1 auto;
    border: 0;
    border-radius: 0;
    background-color: transparent;
    font-size: var(--input-group-font-size, var(--text-md));
    line-height: var(--input-group-line-height, var(--line-height-text-md));
    outline: 0;
    padding-block: var(--input-group-input-padding-y, 0.5rem);
    padding-inline: var(--input-group-input-padding-x, 0.875rem);
  }

  .addon,
  .text {
    box-sizing: border-box;
    display: inline-flex;
    min-width: max-content;
    align-items: center;
    justify-content: center;
    gap: var(--input-group-addon-gap, var(--spacing-2));
    padding-inline: var(--input-group-addon-padding-x, 0.875rem);
    background-color: var(--input-group-addon-bg, var(--color-muted));
    color: var(--input-group-addon-color, var(--color-muted-foreground));
    font-size: var(--input-group-font-size, var(--text-md));
    line-height: var(--input-group-line-height, var(--line-height-text-md));
    white-space: nowrap;

    & > svg {
      width: var(--input-group-icon-size, 1rem);
      height: var(--input-group-icon-size, 1rem);
      flex-shrink: 0;
    }
  }

  .addon {
    border-inline: var(--input-group-separator-width, var(--border-width-sm)) solid
      var(--input-group-separator-color, var(--color-border));

    &:first-child {
      border-inline-start: 0;
    }

    &:last-child {
      border-inline-end: 0;
    }
  }

  .text {
    background-color: transparent;
  }

  .button {
    min-height: auto;
    height: auto;
    align-self: stretch;
    padding-block: 0;
    padding-inline: var(--input-group-addon-padding-x, 0.875rem);
    border: 0;
    border-radius: 0;
    color: var(--input-group-button-color, var(--color-foreground));
    font-size: var(--input-group-font-size, var(--text-sm));
    line-height: var(--input-group-line-height, var(--line-height-text-sm));

    &:focus-visible {
      outline-offset: var(--input-group-button-focus-ring-offset, -1px);
    }
  }
}
